  1→/**
  2→ * Interaction API Client
  3→ *
  4→ * TypeScript client for Interaction API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on interactions.
  6→ */
  7→
  8→import type {
  9→  InteractionData,
 10→  InteractionFilters,
 11→  InteractionCreateInput,
 12→  InteractionUpdateInput,
 13→  ApiListResponse,
 14→  ApiResponse,
 15→  ApiClientConfig,
 16→} from './types';
 17→import { ApiClientError, parseApiError, parseJson } from './shared';
 18→
 19→export { ApiClientError } from './shared';
 20→
 21→/**
 22→ * Default base URL for API requests
 23→ */
 24→const DEFAULT_BASE_URL = '/api';
 25→
 26→/**
 27→ * Interaction API Client
 28→ *
 29→ * Provides typed methods for Interaction CRUD operations.
 30→ * All methods return typed data or throw ApiClientError.
 31→ */
 32→export class InteractionApiClient {
 33→  private baseUrl: string;
 34→  private fetchFn: typeof globalThis.fetch;
 35→  private defaultHeaders: Record<string, string>;
 36→
 37→  constructor(config: ApiClientConfig = {}) {
 38→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 39→    this.fetchFn = config.fetch ?? fetch;
 40→    this.defaultHeaders = {
 41→      'Content-Type': 'application/json',
 42→      ...config.headers,
 43→    };
 44→  }
 45→
 46→  /**
 47→   * Build full URL for endpoint
 48→   */
 49→  private url(path: string, params?: Record<string, string | undefined>): string {
 50→    const fullUrl = `${this.baseUrl}${path}`;
 51→
 52→    if (params) {
 53→      const searchParams = new URLSearchParams();
 54→      for (const [key, value] of Object.entries(params)) {
 55→        if (value !== undefined) {
 56→          searchParams.append(key, value);
 57→        }
 58→      }
 59→      const queryString = searchParams.toString();
 60→      if (queryString) {
 61→        return `${fullUrl}?${queryString}`;
 62→      }
 63→    }
 64→
 65→    return fullUrl;
 66→  }
 67→
 68→  /**
 69→   * GET /api/interactions
 70→   *
 71→   * List all interactions with optional filtering.
 72→   * Supports filtering by contactId and type.
 73→   *
 74→   * @returns Array of interactions with count
 75→   */
 76→  async getInteractions(filters?: InteractionFilters): Promise<ApiListResponse<InteractionData>> {
 77→    const response = await this.fetchFn(
 78→      this.url('/interactions', {
 79→        contactId: filters?.contactId,
 80→        type: filters?.type,
 81→      }),
 82→      {
 83→        headers: this.defaultHeaders,
 84→      }
 85→    );
 86→
 87→    if (!response.ok) {
 88→      return parseApiError(response);
 89→    }
 90→
 91→    return parseJson<ApiListResponse<InteractionData>>(response);
 92→  }
 93→
 94→  /**
 95→   * GET /api/interactions/[id]
 96→   *
 97→   * Fetch a single interaction by ID.
 98→   *
 99→   * @param id - Interaction UUID
100→   * @returns Interaction data
101→   * @throws ApiClientError with 404 if not found
102→   */
103→  async getInteraction(id: string): Promise<ApiResponse<InteractionData>> {
104→    if (!id) {
105→      throw new ApiClientError(400, 'Validation failed', 'id is required');
106→    }
107→
108→    const response = await this.fetchFn(this.url(`/interactions/${id}`), {
109→      headers: this.defaultHeaders,
110→    });
111→
112→    if (!response.ok) {
113→      return parseApiError(response);
114→    }
115→
116→    return parseJson<ApiResponse<InteractionData>>(response);
117→  }
118→
119→  /**
120→   * POST /api/interactions
121→   *
122→   * Create a new interaction.
123→   * Validates required fields: contactId, type, authorId.
124→   *
125→   * @param data - Interaction creation input
126→   * @returns Created interaction data
127→   * @throws ApiClientError with 400 on validation errors
128→   */
129→  async createInteraction(data: InteractionCreateInput): Promise<ApiResponse<InteractionData>> {
130→    const response = await this.fetchFn(this.url('/interactions'), {
131→      method: 'POST',
132→      headers: this.defaultHeaders,
133→      body: JSON.stringify(data),
134→    });
135→
136→    if (!response.ok) {
137→      return parseApiError(response);
138→    }
139→
140→    return parseJson<ApiResponse<InteractionData>>(response);
141→  }
142→
143→  /**
144→   * PUT /api/interactions/[id]
145→   *
146→   * Update an existing interaction.
147→   * Only provided fields are updated (partial update).
148→   *
149→   * @param id - Interaction UUID
150→   * @param data - Interaction update input (all fields optional)
151→   * @returns Updated interaction data
152→   * @throws ApiClientError with 404 if interaction not found
153→   */
154→  async updateInteraction(
155→    id: string,
156→    data: InteractionUpdateInput
157→  ): Promise<ApiResponse<InteractionData>> {
158→    if (!id) {
159→      throw new ApiClientError(400, 'Validation failed', 'id is required');
160→    }
161→
162→    const response = await this.fetchFn(this.url(`/interactions/${id}`), {
163→      method: 'PUT',
164→      headers: this.defaultHeaders,
165→      body: JSON.stringify(data),
166→    });
167→
168→    if (!response.ok) {
169→      return parseApiError(response);
170→    }
171→
172→    return parseJson<ApiResponse<InteractionData>>(response);
173→  }
174→
175→  /**
176→   * DELETE /api/interactions/[id]
177→   *
178→   * Hard delete an interaction.
179→   *
180→   * @param id - Interaction UUID
181→   * @returns Deleted interaction data with success message
182→   * @throws ApiClientError with 404 if interaction not found
183→   */
184→  async deleteInteraction(id: string): Promise<ApiResponse<InteractionData> & { message: string }> {
185→    if (!id) {
186→      throw new ApiClientError(400, 'Validation failed', 'id is required');
187→    }
188→
189→    const response = await this.fetchFn(this.url(`/interactions/${id}`), {
190→      method: 'DELETE',
191→      headers: this.defaultHeaders,
192→    });
193→
194→    if (!response.ok) {
195→      return parseApiError(response);
196→    }
197→
198→    return parseJson<ApiResponse<InteractionData> & { message: string }>(response);
199→  }
200→
201→  /**
202→   * GET /api/contacts/[id]/interactions
203→   *
204→   * Fetch the interaction timeline for a specific contact.
205→   * Returns interactions ordered by createdAt descending with author info.
206→   *
207→   * @param contactId - Contact UUID
208→   * @returns Array of interactions with author data
209→   * @throws ApiClientError with 404 if contact doesn't exist
210→   */
211→  async getContactInteractions(contactId: string): Promise<ApiListResponse<InteractionData>> {
212→    if (!contactId) {
213→      throw new ApiClientError(400, 'Validation failed', 'contactId is required');
214→    }
215→
216→    const response = await this.fetchFn(
217→      this.url(`/contacts/${contactId}/interactions`),
218→      {
219→        headers: this.defaultHeaders,
220→      }
221→    );
222→
223→    if (!response.ok) {
224→      return parseApiError(response);
225→    }
226→
227→    return parseJson<ApiListResponse<InteractionData>>(response);
228→  }
229→}
