"use client"

/**
 * Interaction Timeline Component
 *
 * Displays chronological list of interactions for a contact.
 * Fetches interactions on mount, shows loading/error/empty states.
 */

import { useEffect, useState } from "react"
import { Phone, Calendar, Mail, AlertCircle, RefreshCw } from "lucide-react"
import { interactionsApi, ApiClientError } from "@/lib/api/interactions"
import type { InteractionData } from "@/lib/api/types"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"

interface InteractionTimelineProps {
  contactId: string
}

type TimelineState = {
  interactions: InteractionData[]
  loading: boolean
  error: string | null
}

const INTERACTION_TYPE_CONFIG = {
  call: { icon: Phone, label: "Call", variant: "default" as const },
  meeting: { icon: Calendar, label: "Meeting", variant: "secondary" as const },
  email: { icon: Mail, label: "Email", variant: "outline" as const },
  note: { icon: Mail, label: "Note", variant: "ghost" as const },
  task: { icon: Calendar, label: "Task", variant: "outline" as const },
}

const DIRECTION_CONFIG = {
  inbound: { label: "Inbound", variant: "outline" as const },
  outbound: { label: "Outbound", variant: "secondary" as const },
}

/**
 * Format date for display using Intl.DateTimeFormat
 */
function formatDate(dateString: string | null): string {
  if (!dateString) return ""
  const date = new Date(dateString)
  const now = new Date()
  const isThisYear = date.getFullYear() === now.getFullYear()

  const formatter = new Intl.DateTimeFormat(undefined, {
    month: "short",
    day: "numeric",
    year: isThisYear ? undefined : "numeric",
    hour: "2-digit",
    minute: "2-digit",
  })

  return formatter.format(date)
}

/**
 * Get content preview (truncated)
 */
function getContentPreview(content: string | null, maxLength = 100): string {
  if (!content) return ""
  return content.length > maxLength ? content.slice(0, maxLength) + "..." : content
}

export function InteractionTimeline({ contactId }: InteractionTimelineProps) {
  const [state, setState] = useState<TimelineState>({
    interactions: [],
    loading: true,
    error: null,
  })

  useEffect(() => {
    let isMounted = true

    async function fetchInteractions() {
      try {
        setState({ interactions: [], loading: true, error: null })
        const response = await interactionsApi.getContactInteractions(contactId)

        if (isMounted) {
          setState({
            interactions: response.data,
            loading: false,
            error: null,
          })
        }
      } catch (error) {
        if (isMounted) {
          const message =
            error instanceof ApiClientError
              ? error.message
              : "Failed to load interactions"
          console.error("Error fetching interactions:", error)
          setState({
            interactions: [],
            loading: false,
            error: message,
          })
        }
      }
    }

    fetchInteractions()

    return () => {
      isMounted = false
    }
  }, [contactId])

  function handleRetry() {
    setState({ interactions: [], loading: true, error: null })
  }

  // Loading state
  if (state.loading) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-8">
          <div className="flex items-center gap-2 text-muted-foreground">
            <div className="h-4 w-4 animate-spin rounded-full border-2 border-primary border-t-transparent" />
            <span>Loading interactions...</span>
          </div>
        </CardContent>
      </Card>
    )
  }

  // Error state
  if (state.error) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center gap-4 py-8">
          <AlertCircle className="h-8 w-8 text-destructive" />
          <div className="text-center">
            <p className="font-medium">Failed to load interactions</p>
            <p className="text-sm text-muted-foreground">{state.error}</p>
          </div>
          <Button onClick={handleRetry} variant="outline" size="sm">
            <RefreshCw className="mr-2 h-4 w-4" />
            Retry
          </Button>
        </CardContent>
      </Card>
    )
  }

  // Empty state
  if (state.interactions.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center gap-2 py-8">
          <Mail className="h-12 w-12 text-muted-foreground/50" />
          <p className="text-muted-foreground">No interactions yet</p>
        </CardContent>
      </Card>
    )
  }

  // Timeline view
  return (
    <div className="space-y-3">
      {state.interactions.map((interaction) => {
        const typeConfig = INTERACTION_TYPE_CONFIG[interaction.type as keyof typeof INTERACTION_TYPE_CONFIG] || INTERACTION_TYPE_CONFIG.note
        const TypeIcon = typeConfig.icon

        return (
          <Card key={interaction.id} size="sm">
            <CardHeader className="pb-2">
              <div className="flex items-start justify-between gap-2">
                <div className="flex items-center gap-2">
                  <TypeIcon className="h-4 w-4 text-muted-foreground" />
                  <CardTitle className="text-sm">
                    {interaction.subject || typeConfig.label}
                  </CardTitle>
                </div>
                <Badge variant={typeConfig.variant} size="xs">
                  {typeConfig.label}
                </Badge>
              </div>
            </CardHeader>
            {interaction.content && (
              <CardContent className="pt-0">
                <p className="text-sm text-muted-foreground line-clamp-3">
                  {getContentPreview(interaction.content)}
                </p>
              </CardContent>
            )}
            <CardFooter className="py-2">
              <div className="flex items-center gap-3 text-xs text-muted-foreground">
                <span>{formatDate(interaction.createdAt)}</span>
                {interaction.direction && (
                  <Badge
                    variant={DIRECTION_CONFIG[interaction.direction as keyof typeof DIRECTION_CONFIG]?.variant || "outline"}
                    size="xs"
                  >
                    {DIRECTION_CONFIG[interaction.direction as keyof typeof DIRECTION_CONFIG]?.label || interaction.direction}
                  </Badge>
                )}
                {interaction.authorId && (
                  <span>by {interaction.authorId.slice(0, 8)}</span>
                )}
              </div>
            </CardFooter>
          </Card>
        )
      })}
    </div>
  )
}

